local IsDebug = false
local DEFAULT_PUSH_SIZE = 1024 * 4 ---4kb
local GameType = "g1000"
local AutoCache = true
local TmpCaches = {}
local Caches = {}
local WaitSaveCache = {}
local PushCacheTime = 0
local PushCacheLock = {}
local PushFailedRecord = {}
local TotalCacheSize = 0
local MustLoadSubKey = {}
local GetDataRecords = {}
local PlayerDBSaveFunction
local PlayerDBSaveInterval = 90

DBManager = {}

local function kickOutPlayer(userId)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    if player.isLoginSuccess then
        HostApi.sendGameover(player.rakssid, IMessages:msgGameOverByDBDataError(), GameOverCode.LoadDBDataError)
    else
        LuaTimer:schedule(function()
            kickOutPlayer(userId)
        end, 1000)
    end
end

local function addTmpCache(key, cache)
    TmpCaches[key] = cache
end

local function getTmpCache(key)
    return TmpCaches[key]
end

local function removeTmpCache(userId)
    local uid = tostring(userId)
    local rms = {}
    for key, cache in pairs(TmpCaches) do
        local params = StringUtil.split(key, "#")
        if params[1] == uid then
            table.insert(rms, key)
        end
    end
    for _, key in pairs(rms) do
        TmpCaches[key] = nil
    end
end

local function addCache(key, data)
    local cache = TableUtil.copyTable(data)
    cache.__first = nil
    cache.subKey = nil
    cache.userId = nil
    Caches[key] = cache
    return cache
end

local function getCache(key)
    return Caches[key]
end

local function isPlayerDBReady(userId)
    if #MustLoadSubKey == 0 then
        return true
    end
    local uid = tostring(userId)
    local record = GetDataRecords[uid]
    if not record then
        return false
    end
    for _, key in pairs(MustLoadSubKey) do
        if not record.keys[key] then
            return false
        end
    end
    return true
end

local function addGetDataRecord(userId, subKey)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return
    end
    local uid = tostring(userId)
    local record = GetDataRecords[uid]
    if not record then
        record = { keys = {}, isReady = false }
    end
    record.keys[subKey] = true
    GetDataRecords[uid] = record
    if not isPlayerDBReady(userId) then
        return
    end
    PacketSender:sendPlayerDBReady(player.rakssid)
end

local function canSaveDBData(userId)
    local uid = tostring(userId)
    local record = GetDataRecords[uid]
    if not record then
        return false
    end
    return record.isReady and isPlayerDBReady(userId)
end

---判读当前数据是否处于需要保存的状态
---如果在保存队列里面或者在Http请求没返回之前，都算处于需要保存状态
local function isDataSaving(userId, subKey)
    local key = tostring(userId) .. "#" .. subKey
    for _, cache in pairs(WaitSaveCache) do
        if cache.key == key then
            return true
        end
    end
    return PushCacheLock[key] == true
end

local function getGameData(userId, subKey, times, func, isRetry)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player then
        if PlayerManager:isAIPlayer(player) then
            return
        end
    end
    local key = tostring(userId) .. "#" .. subKey
    local cache = getCache(key)
    if cache then
        if TableUtil.isEmpty(cache) then
            cache = { __first = true }
        end
        func(userId, subKey, cache)
        cache.__first = nil
        return
    end
    if isDataSaving(userId, subKey) then
        ---需要把所有需要保存的数据保存完成才能获取Http数据，否则延迟1秒获取
        LuaTimer:schedule(function()
            getGameData(userId, subKey, times, func, isRetry)
        end, 1000)
        return
    end
    WebService:GetUserGameData(userId, subKey, isRetry, function(data)
        if not data then
            if times > 0 then
                times = times - 1
                getGameData(userId, subKey, times, func, true)
            else
                kickOutPlayer(userId)
                HostApi.log(string.format("[Error] get game data failed! userId: %s, subKey: %s", tostring(userId), tostring(subKey)))
                GetDBDataErrorEvent:invoke(userId, subKey)
            end
            return
        end
        func(userId, subKey, data)
    end)
end

local function saveGameData(body, result, times, isRetry)
    WebService:SaveUserGameData(result, isRetry, function(code)
        local clearLock = function()
            for _, cache in pairs(body) do
                local key = cache.userId .. "#" .. cache.subKey
                PushCacheLock[key] = nil
            end
        end
        if code ~= 1 then
            if times > 0 then
                times = times - 1
                saveGameData(body, result, times, true)
            else
                clearLock()
                local keys = {}
                for _, cache in pairs(body) do
                    local key = cache.userId .. "#" .. cache.subKey
                    keys[key] = cache
                end
                for key, cache in pairs(keys) do
                    local record = PushFailedRecord[key]
                    if not record then
                        record = { userId = cache.userId, subKey = cache.subKey, times = 0 }
                    end
                    record.times = record.times + 1
                    PushFailedRecord[key] = record
                end
                local removeTmp = {}
                local removeFailed = {}
                local retryCache = {}
                for _, cache in pairs(body) do
                    local key = cache.userId .. "#" .. cache.subKey
                    if PushFailedRecord[key].times >= 3 then
                        removeFailed[key] = true
                        HostApi.log("[SCRIPT_EXCEPTION] save player data failed! result: " .. json.encode(cache))
                        local c_cache = getTmpCache(key)
                        if c_cache then
                            HostApi.log(string.format("[Cache][userId: %s, subKey: %s] player data tmp cache: %s",
                                    cache.userId, cache.subKey, json.encode(c_cache)))
                        end
                        local player = PlayerManager:getPlayerByUserId(cache.userId)
                        if player then
                            kickOutPlayer(cache.userId)
                            SaveDBDataErrorEvent:invoke(cache.userId, cache.subKey)
                        else
                            table.insert(removeTmp, cache.userId)
                        end
                        OrderManager.restoreOrder(cache.userId, cache.subKey)
                    else
                        local item = {
                            key = key,
                            data = cache,
                            size = TableUtil.getTableByte(cache)
                        }
                        table.insert(retryCache, item)
                        TotalCacheSize = TotalCacheSize + item.size
                    end
                end
                TableUtil.appendArray(retryCache, WaitSaveCache)
                WaitSaveCache = retryCache
                for _, userId in pairs(removeTmp) do
                    removeTmpCache(userId)
                end
                for key, _ in pairs(removeFailed) do
                    PushFailedRecord[key] = nil
                end
            end
        else
            clearLock()
            for _, cache in pairs(body) do
                local key = cache.userId .. "#" .. cache.subKey
                PushFailedRecord[key] = nil
                OrderManager.consumeOrder(cache.userId, cache.subKey)
            end
        end
    end)
end

---添加(配置)进入游戏前必须加载的subKey，可传多个subKey
---未加载完成玩家进不去游戏，看不见世界
function DBManager:addMustLoadSubKey(...)
    local keys = { ... }
    while #keys > 0 do
        local add = keys[1]
        local find = false
        for _, key in pairs(MustLoadSubKey) do
            if key == add then
                find = true
                break
            end
        end
        if not find then
            table.insert(MustLoadSubKey, add)
        end
        table.remove(keys, 1)
    end
end

---玩家登陆的时候提前加载必要加载的数据
function DBManager:onPlayerLogin(player)
    if #MustLoadSubKey == 0 then
        return true
    end
    if canSaveDBData(player.userId) then
        return true
    end
    for _, key in pairs(MustLoadSubKey) do
        DBManager:getPlayerData(player.userId, key, function(userId, subKey, data)
            addGetDataRecord(userId, subKey)
        end)
    end
    return false
end

function DBManager:onPlayerReady(player)
    local uid = tostring(player.userId)
    local record = GetDataRecords[uid]
    if not record then
        record = { keys = {}, isReady = true }
    else
        record.isReady = true
    end
    GetDataRecords[uid] = record
end

