---删除玩家的数据缓存
function DBManager:removeCache(userId, keys, immediate)
    if not immediate or PlayerManager:getPlayerByUserId(userId) then
        LuaTimer:schedule(function()
            DBManager:removeCache(userId, keys, PlayerManager:getPlayerByUserId(userId) == nil)
        end, 1000)
        return
    end
    local oldKeys
    if keys ~= nil then
        oldKeys = TableUtil.copyTable(keys)
        for pos, key in pairs(keys) do
            keys[pos] = tostring(key)
        end
    end
    local uid = tostring(userId)
    local rms = {}
    for key, cache in pairs(Caches) do
        local params = StringUtil.split(key, "#")
        if params[1] == uid and (keys == nil or TableUtil.include(keys, params[2])) then
            table.insert(rms, key)
        end
    end
    local function clear()
        if PlayerManager:getPlayerByUserId(userId) then
            ---玩家还在线，不需要清除缓存
            return
        end
        for _, key in pairs(rms) do
            Caches[key] = nil
            PushCacheLock[key] = nil
            PushFailedRecord[key] = nil
        end
        GetDataRecords[uid] = nil
        removeTmpCache(userId)
    end
    local function checkHasSave()
        for _, key in pairs(rms) do
            if PushCacheLock[key] then
                return true
            end
            for _, saveCache in pairs(WaitSaveCache) do
                if saveCache.key == key then
                    return true
                end
            end
        end
        return false
    end
    local function delayClear()
        if checkHasSave() then
            LuaTimer:schedule(function()
                delayClear()
            end, 6000)
        else
            clear()
        end
    end
    delayClear()
end

---添加玩家的数据缓存
function DBManager:addCache(userId, subKey, data)
    local key = tostring(userId) .. "#" .. subKey
    local cache = addCache(key, data)
    addTmpCache(key, cache)
end

function DBManager:replaceCache(userId, subKey, data)
    local key = tostring(userId) .. "#" .. subKey
    ---删除缓存记录
    PushFailedRecord[key] = nil
    PushCacheLock[key] = nil
    local find = true
    while find do
        for pos, _cache in pairs(WaitSaveCache) do
            if _cache.key == key then
                table.remove(WaitSaveCache, pos)
                break
            end
        end
        find = false
    end
    local cache = getCache(key) ---旧的本地数据
    if cache then
        ---新的Web端数据，存到缓存里面
        DBManager:addCache(userId, subKey, data)
        ---存在旧的本地数据，执行一次存储操作，将本地数据推送到远端
        self:savePlayerData(userId, subKey, cache, true)
    end
end

function DBManager:onTick(ticks)
    if PlayerDBSaveFunction ~= nil and ticks % PlayerDBSaveInterval == 0 then
        local players = PlayerManager:getPlayers()
        for _, player in pairs(players) do
            if not player.isKickOut and player:checkReady() then
                PlayerDBSaveFunction(player, false)
            end
        end
    end
    if #WaitSaveCache == 0 then
        return
    end
    if os.time() - PushCacheTime > 60 or
            #WaitSaveCache >= 20 or
            GameServer:isCloseServer() or
            TotalCacheSize >= DEFAULT_PUSH_SIZE then
        self:saveAllDataCache()
    end
end

function DBManager:saveAllDataCache()
    if #WaitSaveCache == 0 then
        return
    end
    local total = 0
    local body = {}
    local function findCache()
        local locks = {}
        local find = true
        while find do
            local iFind = false
            for pos, cache in pairs(WaitSaveCache) do
                if not PushCacheLock[cache.key] then
                    if total < DEFAULT_PUSH_SIZE then
                        iFind = true
                        locks[cache.key] = true
                        total = total + cache.size
                        TotalCacheSize = TotalCacheSize - cache.size
                        table.insert(body, cache.data)
                        table.remove(WaitSaveCache, pos)
                        break
                    end
                end
            end
            find = iFind
        end
        for key, _ in pairs(locks) do
            PushCacheLock[key] = true
        end
        return total > 0
    end
    while findCache() do
        saveGameData(TableUtil.copyTable(body), json.encode(body), 3, false)
        total = 0
        body = {}
    end
    PushCacheTime = os.time()
end

---保存玩家数据库数据
---@userId 玩家ID
---@subKey 数据类型，可传string或number
---@data 数据 table
---@immediate 是否及时缓存 boolean
function DBManager:savePlayerData(userId, subKey, data, immediate)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player then
        if PlayerManager:isAIPlayer(player) then
            return
        end
        if not player:checkReady() then
            return
        end
    end
    if not canSaveDBData(userId) then
        return
    end
    if type(data) ~= "table" then
        return
    end
    local key = tostring(userId) .. "#" .. subKey
    local cache = getCache(key)
    if not cache then
        print("DBManager:savePlayerData, not cache: [", tostring(userId), "] subKey:", tostring(subKey))
        return
    end
    if TableUtil.isSameTable(cache, data) then
        return
    end
    if IsDebug then
        HostApi.log(string.format("[CacheData][%s][%s] %s", tostring(userId), tostring(subKey), json.encode(cache)))
        HostApi.log(string.format("[ChangeData][%s][%s] %s", tostring(userId), tostring(subKey), json.encode(data)))
    end
    addTmpCache(key, cache)
    addCache(key, data)
    local result = {}
    TableUtil.checkNotExistValue(cache, data, result)
    TableUtil.deleteSameValue(cache, data, result)
    TableUtil.deleteEmptyValue(result)
    if TableUtil.isEmpty(result) then
        return
    end
    if IsDebug then
        HostApi.log(string.format("[Result][%s][%s] %s", tostring(userId), tostring(subKey), json.encode(result)))
    end
    result.userId = tostring(userId)
    result.subKey = tostring(subKey)
    if not immediate or PushCacheLock[key] then
        local item = {
            key = key,
            data = result,
            size = TableUtil.getTableByte(result)
        }
        table.insert(WaitSaveCache, item)
        TotalCacheSize = TotalCacheSize + item.size
        return
    end
    local body = {}
    local function findCache()
        for pos, cache in pairs(WaitSaveCache) do
            if cache.data.userId == result.userId and cache.data.subKey == result.subKey then
                TotalCacheSize = TotalCacheSize - cache.size
                table.insert(body, cache.data)
                table.remove(WaitSaveCache, pos)
                findCache()
                break
            end
        end
    end
    findCache()
    table.insert(body, result)
    saveGameData(body, json.encode(body), 3, false)
    PushCacheLock[key] = true
end

local function loadDataEnd(callbackEnd, userId, subKey, data)
    local success, error = pcall(callbackEnd, userId, subKey, data)
    if not success then
        HostApi.log("[LoadDataEnd]" .. error, 2)
        print(debug.traceback())
        DBManager:removeCache(userId)
        kickOutPlayer(userId)
    end
end

---获取玩家数据库单条数据
---@userId 玩家ID
---@subKey 数据类型，可传string或number
---@func 回调函数，不传回调则会在GetDataFromDBEvent事件返回
function DBManager:getPlayerData(userId, subKey, func)
    if PlayerDBSaveFunction == nil then
        error("PlayerDBSaveFunction is nil!!!!!")
        return
    end
    getGameData(userId, subKey, 3, function(userId, subKey, data)
        if IsDebug then
            HostApi.log(string.format("[GetData][%s][%s]  %s", tostring(userId), tostring(subKey), json.encode(data)))
        end
        local callbackEnd = function(userId, subKey, data)
            if not func then
                GetDataFromDBEvent:invoke(userId, subKey, data)
            else
                if DBManager:isAutoCache() then
                    local player = PlayerManager:getPlayerByUserId(userId)
                    if player ~= nil then
                        DBManager:addCache(userId, subKey, data)
                    end
                end
                func(userId, subKey, data)
            end
        end
        loadDataEnd(callbackEnd, userId, subKey, data)
    end, false)
end

---获取玩家数据库多条数据
---@userId 玩家ID
---@subKeys 数据类型集合，{string, number}
---@func 回调函数，不传回调则会在GetDataFromDBEvent事件返回
function DBManager:getPlayerManyData(userId, subKeys, func)
    local records = {}
    for _, subKey in pairs(subKeys) do
        records[subKey] = false
    end
    local result = {}
    local callbackEnd = function(userId, subKey, data)
        if not func then
            GetDataFromDBEvent:invoke(userId, subKey, data)
        else
            result[subKey] = data
            records[subKey] = true
            for _, record in pairs(records) do
                if not record then
                    return
                end
            end
            if DBManager:isAutoCache() then
                local player = PlayerManager:getPlayerByUserId(userId)
                if player ~= nil then
                    for _subKey, _data in pairs(result) do
                        DBManager:addCache(userId, _subKey, _data)
                    end
                end
            end
            func(userId, result)
        end
    end
    for _, subKey in pairs(subKeys) do
        self:getPlayerData(userId, subKey, function(userId, subKey, data)
            if IsDebug then
                HostApi.log(string.format("[GetData][%s][%s]  %s", tostring(userId), tostring(subKey), json.encode(data)))
            end
            loadDataEnd(callbackEnd, userId, subKey, data)
        end)
    end
end

---判断数据库数据是否加载成功
---@userId 玩家ID
---@subKey 数据类型
function DBManager:isLoadDataFinished(userId, subKey)
    local key = tostring(userId) .. "#" .. subKey
    return (getCache(key) ~= nil)
end

function DBManager:setPlayerDBSaveFunction(func, timeInterval)
    if type(func) ~= "function" then
        return
    end
    timeInterval = timeInterval or 90
    PlayerDBSaveFunction = func
    PlayerDBSaveInterval = timeInterval
end

function DBManager:callSavePlayerData(player)
    if PlayerDBSaveFunction ~= nil and player:checkReady() then
        PlayerDBSaveFunction(player, true)
    end
end

function DBManager:clearPlayerDBData(player)
    for _, subKey in pairs(MustLoadSubKey) do
        self:savePlayerData(player.userId, subKey, {}, true)
    end
    self:savePlayerData(player.userId, "SumRecharge", {}, true)
    local uid = tostring(player.userId)
    local rms = {}
    for key, _ in pairs(Caches) do
        local params = StringUtil.split(key, "#")
        if params[1] == uid then
            table.insert(rms, key)
        end
    end
    for _, key in pairs(rms) do
        Caches[key] = nil
        PushCacheLock[key] = nil
        PushFailedRecord[key] = nil
    end
    GetDataRecords[uid] = nil
    removeTmpCache(uid)
end

function DBManager:hasDataSaving(userId)
    userId = tostring(userId)
    for _, cache in pairs(WaitSaveCache) do
        if StringUtil.split(cache.key, "#")[1] == userId then
            return true
        end
    end
    for key, _ in pairs(PushCacheLock) do
        if StringUtil.split(key, "#")[1] == userId then
            return true
        end
    end
    return false
end

return DBManager